package com.example.debug;

import com.google.rpc.Code;
import io.grpc.stub.StreamObserver;

import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class DebugServiceImpl extends DebugServiceGrpc.DebugServiceImplBase {

    private final ConcurrentHashMap<String, UserData> userCache = new ConcurrentHashMap<>();
    private final String dbUrl;
    private final String dbUser;
    private final String dbPassword;

    public DebugServiceImpl(String dbUrl, String dbUser, String dbPassword) {
        this.dbUrl = dbUrl;
        this.dbUser = dbUser;
        this.dbPassword = dbPassword;
    }

    public DebugServiceImpl() {
        this("jdbc:postgresql://localhost:5432/debugdb", "user", "password");
    }

    @Override
    public void getUser(GetUserRequest request, StreamObserver<GetUserResponse> responseObserver) {
        String userId = request.getUserId();

        try {
            // Validate input
            if (userId == null || userId.trim().isEmpty()) {
                Map<String, String> state = new HashMap<>();
                state.put("request_user_id", String.valueOf(userId));
                state.put("validation_rule", "user_id must not be null or empty");
                state.put("service_method", "getUser");
                state.put("timestamp", String.valueOf(System.currentTimeMillis()));

                throw new IllegalArgumentException("User ID is required but was: '" + userId + "'");
            }

            // Try cache first
            UserData cached = userCache.get(userId);
            if (cached != null) {
                responseObserver.onNext(GetUserResponse.newBuilder()
                        .setUserId(cached.userId)
                        .setName(cached.name)
                        .setEmail(cached.email)
                        .build());
                responseObserver.onCompleted();
                return;
            }

            // Query database
            String query = "SELECT user_id, name, email FROM users WHERE user_id = ?";
            try (Connection conn = DriverManager.getConnection(dbUrl, dbUser, dbPassword);
                 PreparedStatement stmt = conn.prepareStatement(query)) {

                stmt.setString(1, userId);
                ResultSet rs = stmt.executeQuery();

                if (rs.next()) {
                    UserData userData = new UserData(
                            rs.getString("user_id"),
                            rs.getString("name"),
                            rs.getString("email")
                    );
                    userCache.put(userId, userData);

                    responseObserver.onNext(GetUserResponse.newBuilder()
                            .setUserId(userData.userId)
                            .setName(userData.name)
                            .setEmail(userData.email)
                            .build());
                    responseObserver.onCompleted();
                } else {
                    Map<String, String> state = new HashMap<>();
                    state.put("queried_user_id", userId);
                    state.put("query", query);
                    state.put("cache_size", String.valueOf(userCache.size()));
                    state.put("cache_keys", userCache.keySet().toString());
                    state.put("db_url", dbUrl);

                    throw new UserNotFoundException("User not found with ID: " + userId, state);
                }

            } catch (SQLException e) {
                responseObserver.onError(ErrorDetailHelper.fromSQLException(e, query));
            }

        } catch (UserNotFoundException e) {
            responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                    Code.NOT_FOUND,
                    e.getMessage(),
                    e,
                    e.getInternalState(),
                    null
            ));
        } catch (IllegalArgumentException e) {
            Map<String, String> state = new HashMap<>();
            state.put("request_user_id", String.valueOf(userId));
            state.put("service_method", "getUser");

            responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                    Code.INVALID_ARGUMENT,
                    e.getMessage(),
                    e,
                    state,
                    null
            ));
        } catch (Exception e) {
            Map<String, String> state = new HashMap<>();
            state.put("request_user_id", userId);
            state.put("cache_state", userCache.toString());
            state.put("thread_name", Thread.currentThread().getName());
            state.put("available_memory", String.valueOf(Runtime.getRuntime().freeMemory()));
            state.put("total_memory", String.valueOf(Runtime.getRuntime().totalMemory()));

            responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                    Code.INTERNAL,
                    "Internal error processing getUser: " + e.getMessage(),
                    e,
                    state,
                    null
            ));
        }
    }

    @Override
    public void updateUser(UpdateUserRequest request, StreamObserver<UpdateUserResponse> responseObserver) {
        String userId = request.getUserId();
        String name = request.getName();
        String email = request.getEmail();
        String query = "UPDATE users SET name = ?, email = ? WHERE user_id = ?";

        try {
            // Validate
            Map<String, String> validationState = new HashMap<>();
            validationState.put("user_id", String.valueOf(userId));
            validationState.put("name", String.valueOf(name));
            validationState.put("email", String.valueOf(email));

            if (userId == null || userId.trim().isEmpty()) {
                validationState.put("failed_field", "user_id");
                responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                        Code.INVALID_ARGUMENT,
                        "User ID is required for update",
                        new IllegalArgumentException("Missing user_id in UpdateUserRequest"),
                        validationState,
                        null
                ));
                return;
            }

            if (email != null && !email.contains("@")) {
                validationState.put("failed_field", "email");
                validationState.put("validation_rule", "email must contain '@'");
                responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                        Code.INVALID_ARGUMENT,
                        "Invalid email format: " + email,
                        new IllegalArgumentException("Invalid email: " + email),
                        validationState,
                        null
                ));
                return;
            }

            try (Connection conn = DriverManager.getConnection(dbUrl, dbUser, dbPassword);
                 PreparedStatement stmt = conn.prepareStatement(query)) {

                stmt.setString(1, name);
                stmt.setString(2, email);
                stmt.setString(3, userId);

                int rowsAffected = stmt.executeUpdate();

                if (rowsAffected == 0) {
                    Map<String, String> state = new HashMap<>();
                    state.put("user_id", userId);
                    state.put("rows_affected", "0");
                    state.put("query", query);
                    state.put("params", String.format("name=%s, email=%s, user_id=%s", name, email, userId));

                    responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                            Code.NOT_FOUND,
                            "No user found to update with ID: " + userId,
                            new UserNotFoundException("User " + userId + " not found for update", state),
                            state,
                            null
                    ));
                    return;
                }

                // Update cache
                userCache.put(userId, new UserData(userId, name, email));

                responseObserver.onNext(UpdateUserResponse.newBuilder()
                        .setSuccess(true)
                        .build());
                responseObserver.onCompleted();

            } catch (SQLException e) {
                responseObserver.onError(ErrorDetailHelper.fromSQLException(e, query));
            }

        } catch (Exception e) {
            Map<String, String> state = new HashMap<>();
            state.put("user_id", userId);
            state.put("operation", "updateUser");
            state.put("thread", Thread.currentThread().getName());
            state.put("timestamp", String.valueOf(System.currentTimeMillis()));

            responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                    Code.INTERNAL,
                    "Failed to update user: " + e.getMessage(),
                    e,
                    state,
                    null
            ));
        }
    }

    @Override
    public void queryDatabase(QueryRequest request, StreamObserver<QueryResponse> responseObserver) {
        String rawQuery = request.getQuery();

        try {
            if (rawQuery == null || rawQuery.trim().isEmpty()) {
                Map<String, String> state = new HashMap<>();
                state.put("raw_query", String.valueOf(rawQuery));
                state.put("operation", "queryDatabase");

                responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                        Code.INVALID_ARGUMENT,
                        "Query string is required",
                        new IllegalArgumentException("Empty query provided"),
                        state,
                        null
                ));
                return;
            }

            // Security check - expose details for debugging
            String upperQuery = rawQuery.toUpperCase().trim();
            if (upperQuery.startsWith("DROP") || upperQuery.startsWith("DELETE") ||
                    upperQuery.startsWith("TRUNCATE") || upperQuery.startsWith("ALTER")) {

                Map<String, String> state = new HashMap<>();
                state.put("blocked_query", rawQuery);
                state.put("query_type", upperQuery.split("\\s+")[0]);
                state.put("security_rule", "Destructive queries are not allowed via this endpoint");
                state.put("allowed_types", "SELECT, INSERT, UPDATE");

                responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                        Code.PERMISSION_DENIED,
                        "Destructive query blocked: " + rawQuery,
                        new SecurityException("Blocked destructive query: " + rawQuery),
                        state,
                        null
                ));
                return;
            }

            try (Connection conn = DriverManager.getConnection(dbUrl, dbUser, dbPassword);
                 PreparedStatement stmt = conn.prepareStatement(rawQuery)) {

                ResultSet rs = stmt.executeQuery();
                QueryResponse.Builder responseBuilder = QueryResponse.newBuilder();

                int columnCount = rs.getMetaData().getColumnCount();
                while (rs.next()) {
                    StringBuilder row = new StringBuilder();
                    for (int i = 1; i <= columnCount; i++) {
                        if (i > 1) row.append(" | ");
                        row.append(rs.getMetaData().getColumnName(i))
                                .append("=")
                                .append(rs.getString(i));
                    }
                    responseBuilder.addResults(row.toString());
                }

                responseObserver.onNext(responseBuilder.build());
                responseObserver.onCompleted();

            } catch (SQLException e) {
                responseObserver.onError(ErrorDetailHelper.fromSQLException(e, rawQuery));
            }

        } catch (Exception e) {
            Map<String, String> state = new HashMap<>();
            state.put("raw_query", rawQuery);
            state.put("operation", "queryDatabase");
            state.put("db_url", dbUrl);
            state.put("thread", Thread.currentThread().getName());

            responseObserver.onError(ErrorDetailHelper.buildDetailedError(
                    Code.INTERNAL,
                    "Query execution failed: " + e.getMessage(),
                    e,
                    state,
                    null
            ));
        }
    }

    // Internal data class
    private static class UserData {
        final String userId;
        final String name;
        final String email;

        UserData(String userId, String name, String email) {
            this.userId = userId;
            this.name = name;
            this.email = email;
        }

        @Override
        public String toString() {
            return "UserData{userId='" + userId + "', name='" + name + "', email='" + email + "'}";
        }
    }
}


