package com.example.debug;

import java.util.HashMap;
import java.util.Map;

public class UserNotFoundException extends RuntimeException {
    private final Map<String, String> internalState;

    public UserNotFoundException(String message) {
        super(message);
        this.internalState = new HashMap<>();
    }

    public UserNotFoundException(String message, Map<String, String> internalState) {
        super(message);
        this.internalState = internalState != null ? internalState : new HashMap<>();
    }

    public UserNotFoundException(String message, Throwable cause, Map<String, String> internalState) {
        super(message, cause);
        this.internalState = internalState != null ? internalState : new HashMap<>();
    }

    public Map<String, String> getInternalState() {
        return internalState;
    }
}


