package com.example.debug;

import com.google.protobuf.Any;
import com.google.rpc.Code;
import com.google.rpc.DebugInfo;
import com.google.rpc.ErrorInfo;
import com.google.rpc.Status;
import io.grpc.*;
import io.grpc.protobuf.StatusProto;

import java.io.PrintWriter;
import java.io.StringWriter;
import java.util.HashMap;
import java.util.Map;

public class DebugInterceptor implements ServerInterceptor {

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        ServerCall<ReqT, RespT> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
            @Override
            public void close(io.grpc.Status status, Metadata trailers) {
                if (!status.isOk() && status.getCause() != null) {
                    Throwable cause = status.getCause();

                    // If the error doesn't already have rich details, add them
                    if (!(cause instanceof StatusRuntimeException)) {
                        StringWriter sw = new StringWriter();
                        cause.printStackTrace(new PrintWriter(sw));

                        Map<String, String> metadata = new HashMap<>();
                        metadata.put("intercepted", "true");
                        metadata.put("original_code", status.getCode().name());
                        metadata.put("method", call.getMethodDescriptor().getFullMethodName());
                        metadata.put("exception_type", cause.getClass().getName());
                        metadata.put("full_trace", sw.toString());
                        metadata.put("thread", Thread.currentThread().getName());
                        metadata.put("timestamp", String.valueOf(System.currentTimeMillis()));

                        Status richStatus = Status.newBuilder()
                                .setCode(convertCode(status.getCode()).getNumber())
                                .setMessage(status.getDescription() != null ?
                                        status.getDescription() : cause.getMessage())
                                .addDetails(Any.pack(DebugInfo.newBuilder()
                                        .setDetail(sw.toString())
                                        .build()))
                                .addDetails(Any.pack(ErrorInfo.newBuilder()
                                        .setReason(cause.getClass().getSimpleName())
                                        .setDomain("com.example.debug")
                                        .putAllMetadata(metadata)
                                        .build()))
                                .build();

                        StatusRuntimeException sre = StatusProto.toStatusRuntimeException(richStatus);
                        io.grpc.Status newStatus = io.grpc.Status.fromThrowable(sre);
                        Metadata newTrailers = io.grpc.Status.trailersFromThrowable(sre);
                        if (newTrailers != null) {
                            trailers.merge(newTrailers);
                        }
                        super.close(newStatus, trailers);
                        return;
                    }
                }
                super.close(status, trailers);
            }
        };

        ServerCall.Listener<ReqT> listener = next.startCall(wrappedCall, headers);

        return new ForwardingServerCallListener.SimpleForwardingServerCallListener<ReqT>(listener) {
            @Override
            public void onHalfClose() {
                try {
                    super.onHalfClose();
                } catch (Exception e) {
                    Map<String, String> state = new HashMap<>();
                    state.put("interceptor_caught", "true");
                    state.put("method", call.getMethodDescriptor().getFullMethodName());
                    state.put("timestamp", String.valueOf(System.currentTimeMillis()));

                    StatusRuntimeException sre = ErrorDetailHelper.buildDetailedError(
                            Code.INTERNAL,
                            "Unhandled exception in " + call.getMethodDescriptor().getFullMethodName() + ": " + e.getMessage(),
                            e,
                            state,
                            null
                    );
                    call.close(io.grpc.Status.fromThrowable(sre),
                            io.grpc.Status.trailersFromThrowable(sre) != null ?
                                    io.grpc.Status.trailersFromThrowable(sre) : new Metadata());
                }
            }
        };
    }

    private Code convertCode(io.grpc.Status.Code grpcCode) {
        switch (grpcCode) {
            case OK: return Code.OK;
            case CANCELLED: return Code.CANCELLED;
            case UNKNOWN: return Code.UNKNOWN;
            case INVALID_ARGUMENT: return Code.INVALID_ARGUMENT;
            case DEADLINE_EXCEEDED: return Code.DEADLINE_EXCEEDED;
            case NOT_FOUND: return Code.NOT_FOUND;
            case ALREADY_EXISTS: return Code.ALREADY_EXISTS;
            case PERMISSION_DENIED: return Code.PERMISSION_DENIED;
            case RESOURCE_EXHAUSTED: return Code.RESOURCE_EXHAUSTED;
            case FAILED_PRECONDITION: return Code.FAILED_PRECONDITION;
            case ABORTED: return Code.ABORTED;
            case OUT_OF_RANGE: return Code.OUT_OF_RANGE;
            case UNIMPLEMENTED: return Code.UNIMPLEMENTED;
            case INTERNAL: return Code.INTERNAL;
            case UNAVAILABLE: return Code.UNAVAILABLE;
            case DATA_LOSS: return Code.DATA_LOSS;
            case UNAUTHENTICATED: return Code.UNAUTHENTICATED;
            default: return Code.UNKNOWN;
        }
    }
}


// === DebugServer.java ===

package com.example.debug;

import io.grpc.Server;
import io.grpc.ServerBuilder;

import java.io.IOException;

public class DebugServer {

    private final int port;
    private Server server;

    public DebugServer(int port) {
        this.port = port;
    }

    public void start() throws IOException {
        server = ServerBuilder.forPort(port)
                .addService(new DebugServiceImpl())
                .intercept(new DebugInterceptor())
                .build()
                .start();

        System.out.println("Debug gRPC Server started on port " + port);

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down gRPC server...");
            DebugServer.this.stop();
            System.out.println("Server shut down.");
        }));
    }

    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        int port = 50051;
        if (args.length > 0) {
            port = Integer.parseInt(args[0]);
        }

        DebugServer server = new DebugServer(port);
        server.start();
        server.blockUntilShutdown();
    }
}


