package com.example.debug;

import com.google.protobuf.Any;
import com.google.protobuf.InvalidProtocolBufferException;
import com.google.rpc.DebugInfo;
import com.google.rpc.ErrorInfo;
import com.google.rpc.Status;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;

import java.util.concurrent.TimeUnit;

public class DebugClient {

    private final ManagedChannel channel;
    private final DebugServiceGrpc.DebugServiceBlockingStub blockingStub;

    public DebugClient(String host, int port) {
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .build();
        blockingStub = DebugServiceGrpc.newBlockingStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public void getUser(String userId) {
        System.out.println("=== Getting user: " + userId + " ===");
        try {
            GetUserResponse response = blockingStub.getUser(
                    GetUserRequest.newBuilder().setUserId(userId).build());
            System.out.println("User found: " + response.getName() + " (" + response.getEmail() + ")");
        } catch (StatusRuntimeException e) {
            handleError(e);
        }
    }

    public void updateUser(String userId, String name, String email) {
        System.out.println("=== Updating user: " + userId + " ===");
        try {
            UpdateUserResponse response = blockingStub.updateUser(
                    UpdateUserRequest.newBuilder()
                            .setUserId(userId)
                            .setName(name)
                            .setEmail(email)
                            .build());
            System.out.println("Update success: " + response.getSuccess());
        } catch (StatusRuntimeException e) {
            handleError(e);
        }
    }

    public void queryDatabase(String query) {
        System.out.println("=== Executing query: " + query + " ===");
        try {
            QueryResponse response = blockingStub.queryDatabase(
                    QueryRequest.newBuilder().setQuery(query).build());
            System.out.println("Results: " + response.getResultsList());
        } catch (StatusRuntimeException e) {
            handleError(e);
        }
    }

    private void handleError(StatusRuntimeException e) {
        System.err.println("gRPC Error: " + e.getStatus());
        System.err.println("Description: " + e.getStatus().getDescription());

        Status status = StatusProto.fromThrowable(e);
        if (status != null) {
            System.err.println("Status Code: " + status.getCode());
            System.err.println("Status Message: " + status.getMessage());
            System.err.println("Details count: " + status.getDetailsCount());

            for (Any detail : status.getDetailsList()) {
                try {
                    if (detail.is(DebugInfo.class)) {
                        DebugInfo debugInfo = detail.unpack(DebugInfo.class);
                        System.err.println("\n--- Debug Info ---");
                        System.err.println("Stack trace detail: " + debugInfo.getDetail());
                        System.err.println("Stack entries:");
                        debugInfo.getStackEntriesList().forEach(entry ->
                                System.err.println("  at " + entry));
                    } else if (detail.is(ErrorInfo.class)) {
                        ErrorInfo errorInfo = detail.unpack(ErrorInfo.class);
                        System.err.println("\n--- Error Info ---");
                        System.err.println("Reason: " + errorInfo.getReason());
                        System.err.println("Domain: " + errorInfo.getDomain());
                        System.err.println("Metadata:");
                        errorInfo.getMetadataMap().forEach((key, value) ->
                                System.err.println("  " + key + " = " + value));
                    } else if (detail.is(InternalStateInfo.class)) {
                        InternalStateInfo stateInfo = detail.unpack(InternalStateInfo.class);
                        System.err.println("\n--- Internal State ---");
                        stateInfo.getStateMap().forEach((key, value) ->
                                System.err.println("  " + key + " = " + value));
                    } else if (detail.is(DatabaseErrorInfo.class)) {
                        DatabaseErrorInfo dbInfo = detail.unpack(DatabaseErrorInfo.class);
                        System.err.println("\n--- Database Error ---");
                        System.err.println("SQL State: " + dbInfo.getSqlState());
                        System.err.println("Error Code: " + dbInfo.getErrorCode());
                        System.err.println("Error Message: " + dbInfo.getErrorMessage());
                        System.err.println("Query: " + dbInfo.getQuery());
                    } else {
                        System.err.println("\n--- Unknown Detail Type ---");
                        System.err.println("Type URL: " + detail.getTypeUrl());
                    }
                } catch (InvalidProtocolBufferException ex) {
                    System.err.println("Failed to unpack detail: " + ex.getMessage());
                }
            }
        }
        System.err.println("========================================\n");
    }

    public static void main(String[] args) throws InterruptedException {
        DebugClient client = new DebugClient("localhost", 50051);

        try {
            // Test various error scenarios
            client.getUser("");              // Should trigger INVALID_ARGUMENT
            client.getUser("nonexistent");   // Should trigger NOT_FOUND or DB error
            client.updateUser("user1", "Test", "invalid-email"); // Should trigger INVALID_ARGUMENT
            client.queryDatabase("DROP TABLE users"); // Should trigger PERMISSION_DENIED
            client.queryDatabase("");        // Should trigger INVALID_ARGUMENT
            client.queryDatabase("SELECT * FROM users"); // May trigger DB connection error
        } finally {
            client.shutdown();
        }
    }
}